    @Override
    public String getUserId() {
        return userId;
    }

    @Override
    public Integer getSeed() {
        return seed;
    }

    @Override
    public Integer getContextWindow() {
        return contextWindow;
    }

    @Override
    public DefaultChatOptions copy() {
        DefaultChatOptions copy = new DefaultChatOptions();
        copy.model = this.model;
