        copy.topP = this.topP;
        copy.systemInstruction = this.systemInstruction;
        copy.stream = this.stream;
        copy.responseFormat = this.responseFormat;
        copy.userId = this.userId;
        copy.seed = this.seed;
        copy.contextWindow = this.contextWindow;
        return copy;
    }

